# --- HELPER FUNCTION TO GET SCALE FACTOR BEFORE MAINWINDOW ---
def get_scale_factor():
    """Get the DPI scale factor before creating main window.
    Used for dialogs that need scaling before MainWindow exists.
    """
    screen = QApplication.primaryScreen()
    device_pixel_ratio = screen.devicePixelRatio()
    geometry = screen.geometry()
    raw_screen_width = geometry.width() * device_pixel_ratio
    resolution_factor = raw_screen_width / 1920
    return resolution_factor / device_pixel_ratio

# --- ŚCIEŻKI I KONFIGURACJA ---
def get_app_dir():
    """Returns the directory where the application is located.
    
    In Nuitka onefile mode (tested with 4.0.5):
      - sys.frozen is NOT set
      - NUITKA_ONEFILE_BINARY is NOT set
      - __file__ points to Temp extraction dir
      - sys.argv[0] points to the REAL exe location (only reliable source)
    """
    argv0 = os.path.abspath(sys.argv[0])
    file_dir = os.path.dirname(os.path.abspath(__file__))
    argv0_dir = os.path.dirname(argv0)
    
    # If argv[0] ends with .exe and its dir differs from __file__ dir,
    # we are running as a compiled onefile executable
    if argv0.lower().endswith('.exe') and argv0_dir != file_dir:
        return argv0_dir
    
    # Regular Python script or non-onefile frozen build
    return file_dir

