def get_icon_from_base64():
    """Decodes the base64 icon and returns a QIcon object."""
    try:
        # 1. Try to load from local file first (high quality)
        logo_path = os.path.join(APP_DIR, "Manual", "OHLC_Forge_Logo.png")
        if os.path.exists(logo_path):
            return QIcon(logo_path)
            
        # 2. Fallback to embedded base64
        if not ICON_BASE64:
            return QIcon()
        icon_data = base64.b64decode(ICON_BASE64)
        pixmap = QPixmap()
        pixmap.loadFromData(icon_data)
        return QIcon(pixmap)
    except Exception:
        # 3. Final fallback
        if os.path.exists("data_dollar_icon_bg.ico"):
            return QIcon("data_dollar_icon_bg.ico")
        return QIcon()






class ExchangeEngine:
    def __init__(self, exchange_id, output_dir, session_offset, signals):
        self.exchange_id = exchange_id
        
        self.sub_folder = "Binance" if exchange_id == 'binance' else "Bybit"
        self.output_dir = output_dir
        if not os.path.exists(self.output_dir):
            os.makedirs(self.output_dir)
        
        self.timezone_offset = int(session_offset)
        self.session_close_hour = (24 - self.timezone_offset) % 24
        self.session_day_adjust = 1 if self.timezone_offset <= 0 else 0
        self.write_date_offset = 0 if self.session_day_adjust == 1 else 1
        
        self.signals = signals
        self.stop_requested = False
        
        if exchange_id == 'binance':
            self.exchange = ccxt.binanceusdm()
        elif exchange_id == 'bybit':
            self.exchange = ccxt.bybit()
        else:
            raise ValueError("Unknown exchange")
            
        self.markets = self.exchange.load_markets()

    def log(self, message):
        self.signals.log_message.emit(message)
    
    def log_update(self, file_basename, percent, run, attempt):
        self.signals.update_line.emit(self.sub_folder, file_basename, percent, run, attempt)

    def dec_prec(self, a):
        s = f"{dec(a):.20f}".rstrip('0')
        return int(len(s) - s.find('.') - 1)

    def get_filename(self, symbol):
        market = self.exchange.market(symbol)
        safe_id = market['id']
        if self.exchange_id == 'binance':
            return os.path.join(self.output_dir, f"{safe_id}.csv")
        else:
            return os.path.join(self.output_dir, f"{safe_id.replace('-BBT', '')}.csv")

    def is_valid_symbol(self, symbol):
        # DEMO RESTRICTION: Only process BTC/USDT and ETH/USDT
        if not (symbol.startswith('BTC/USDT') or symbol.startswith('ETH/USDT')):
            return False

        market = self.markets[symbol]
        status = market.get('info', {}).get('status', '')
        if status == 'PENDING_TRADING':
            return False
        if self.exchange_id == 'binance':
            is_valid_quote = market.get("quote") in ['USDT', 'BUSD']
            is_active = market.get("active") is True
            is_trading = market.get("info", {}).get("status") == "TRADING"
            return is_valid_quote and is_active and is_trading
        elif self.exchange_id == 'bybit':
            return (market['swap'] is True and 
                    market['inverse'] is False and 
                    market['option'] is False)
        return False

    def process_market(self, symbol, mode, pass_num, user_start_date=None):
        if self.stop_requested: return False, False, 1
        if not self.is_valid_symbol(symbol): return True, False, 1

        filename = self.get_filename(symbol)
        market = self.exchange.market(symbol)
        max_attempt_encountered = 1
        
        try:
            existing_dates = set()
            lines = []
            
            calc_start_date_str = '20191231'
            
            if user_start_date:
                dt_user = datetime.strptime(user_start_date, '%Y-%m-%d')
                calc_start_date_str = dt_user.strftime('%Y%m%d')

            if os.path.exists(filename):
                try:
                    with open(filename, 'r') as f:
                        lines = f.readlines()
                    for line in lines:
                        parts = line.split(',')
                        if parts: existing_dates.add(parts[0].strip())
                except Exception as e:
                    self.log(f"Error reading {filename}: {e}")

            if mode == 'update':
                if lines:
                    last_line = lines[-1].strip()
                    last_file_date = str(last_line.split(',')[0])
                    if int(last_file_date) >= int(calc_start_date_str):
                        calc_start_date_str = last_file_date

            elif mode == 'redownload':
                if user_start_date:
                    cut_off_int = int(user_start_date.replace('-', ''))
                    new_lines = []
                    for line in lines:
                        try:
                            line_date = int(line.split(',')[0])
                            if line_date < cut_off_int:
                                new_lines.append(line)
                        except: pass
                else:
                    new_lines = []
                
                # Check what dates remain after cut-off
                existing_dates = set()
                if new_lines:
                    for line in new_lines:
                        parts = line.split(',')
                        if parts: existing_dates.add(parts[0].strip())
                
                if os.path.exists(filename):
                    if new_lines:
                        with open(filename, 'w') as f:
                            f.writelines(new_lines)
                    else:
                        os.remove(filename)

            elif mode == 'fill_gaps':
                pass
            
            if existing_dates:
                oldest_known_date = min(existing_dates)
            else:
                oldest_known_date = "99999999"

            is_history_started_flag = False
            # DEMO RESTRICTION: Calculate initial UTC start time (Force UTC+0)
            utc_date = datetime.strptime(calc_start_date_str, '%Y%m%d').replace(
                hour=0, minute=0, second=0, microsecond=0
            ).replace(tzinfo=timezone.utc)
            
            unix_date = int(utc_date.timestamp() * 1000)
            
            end_date_now = datetime.now(timezone.utc)
            end_unix_date = int(end_date_now.timestamp() * 1000)
            
            current_since = unix_date
            
            price_prec_raw = market['precision']['price']
            tick_size_precision = self.dec_prec(str(price_prec_raw))
            
            data_modified = False
            
            total_days = max(1, (end_unix_date - unix_date) // (24 * 60 * 60 * 1000))
            processed_days = 0
            file_basename = os.path.basename(filename)
            last_logged_percent = -1
            
            one_day_ms = 24 * 60 * 60 * 1000
            lines_to_write = []
            fetch_limit = 1000
            
            all_candles = []
            
            while current_since < end_unix_date:
                if self.stop_requested: break
                
                ohlcv = None
                max_retries = 10
                for attempt in range(max_retries):
                    max_attempt_encountered = max(max_attempt_encountered, attempt + 1)
                    try:
                        # DEMO RESTRICTION: fetch 1d directly
                        ohlcv = self.exchange.fetch_ohlcv(symbol, '1d', since=current_since, limit=fetch_limit)
                        if attempt > 0:
                            self.signals.error_solved.emit(self.sub_folder, file_basename, pass_num, max_retries, attempt + 1)
                        break
                    except Exception as e:
                        error_msg = str(e)
                        if '429' in error_msg or 'Too Many Requests' in error_msg or '-1003' in error_msg:
                            wait_time = min(2 ** attempt * 5, 120)
                            self.log(f"[{pass_num}/2] {self.sub_folder}: {file_basename} - API Rate Limit (Attempt {attempt+1}/{max_retries})")
                            time.sleep(wait_time)
                        elif '-1122' in error_msg or 'Invalid symbol' in error_msg:
                            self.log(f"Symbol {symbol} is invalid/delisted - skipping")
                            return True, False, max_attempt_encountered
                        else:
                            if attempt == max_retries - 1:
                                self.log(f"[{pass_num}/2] {self.sub_folder}: {file_basename} - Max retries reached: {error_msg}")
                                raise
                            self.log(f"[{pass_num}/2] {self.sub_folder}: {file_basename} - Connection Error (Attempt {attempt+1}/{max_retries})")
                            time.sleep(min(2 ** attempt, 10))
                
                if ohlcv:
                    all_candles.extend(ohlcv)
                    current_since = ohlcv[-1][0] + one_day_ms
                    
                    processed_days += len(ohlcv)
                    current_percent = min(100, int((processed_days / total_days) * 100)) if total_days > 0 else 100
                    if current_percent != last_logged_percent:
                        if current_percent < 100:
                            self.log_update(file_basename, current_percent, pass_num, max_attempt_encountered)
                        last_logged_percent = current_percent
                else:
                    break
                    
            if all_candles:
                for candle in all_candles:
                    timestamp, open_p, high_p, low_p, close_p, volume = candle
                    
                    candle_date = datetime.fromtimestamp(timestamp/1000, tz=timezone.utc)
                    date_str = candle_date.strftime('%Y%m%d')
                    
                    if mode in ['fill_gaps', 'update'] and date_str in existing_dates:
                        continue
                        
                    # Skip incomplete candles (today's candle)
                    if candle_date.date() >= end_date_now.date():
                        continue
                        
                    avg_price = (open_p + high_p + low_p + close_p) / 4
                    turnover = avg_price * volume
                    
                    s_open = f"{open_p:.{tick_size_precision}f}"
                    s_high = f"{high_p:.{tick_size_precision}f}"
                    s_low = f"{low_p:.{tick_size_precision}f}"
                    s_close = f"{close_p:.{tick_size_precision}f}"
                    s_turn = f"{turnover:.0f}"
                    
                    line = f"{date_str},{s_open},{s_high},{s_low},{s_close},{s_turn}\n"
                    lines_to_write.append(line)
                    existing_dates.add(date_str)

            
            if lines_to_write:
                with open(filename, "a") as f:
                    f.writelines(lines_to_write)
                data_modified = True

            if mode == 'fill_gaps' and data_modified and os.path.exists(filename):
                try:
                    with open(filename, 'r') as f:
                        lines = [line.strip() for line in f if line.strip()]
                    
                    # Sort lines by date (first column)
                    lines.sort(key=lambda x: int(x.split(',')[0]))
                    
                    with open(filename, 'w') as f:
                        for line in lines:
                            f.write(line + "\n")
                            
                except Exception as e:
                    self.log(f"Error sorting {symbol}: {e}")
            
            if data_modified:
                self.log_update(file_basename, 100, pass_num, max_attempt_encountered)
            
            return True, data_modified, max_attempt_encountered

        except Exception as e:
            self.log(f"Error processing {symbol}: {str(e)}")
            return False, False, 1


# --- WORKER THREAD ---

class WorkerSignals(QObject):
    progress_updated = Signal(int)
    log_message = Signal(str)
    update_line = Signal(str, str, int, int, int)
    error_solved = Signal(str, str, int, int, int)
    finished = Signal()

class UpdateWorker(QThread):
    def __init__(self, exchange_ids, output_dirs, session_hour, mode, fix_date):
        super().__init__()
        self.exchange_ids = exchange_ids
        self.output_dirs = output_dirs
        self.session_hour = session_hour
        self.mode = mode
        self.fix_date = fix_date
        self.signals = WorkerSignals()
        self.engines = []
        self.stop_requested = False
        self.processed_count = 0
        self.total_count = 0
        self.progress_lock = threading.Lock()
        self.exchange_results = {}

    def process_exchange(self, ex_id):
        ex_start_time = datetime.now()
        try:
            self.signals.log_message.emit(f"Initializing {ex_id.upper()}...")
            engine = ExchangeEngine(ex_id, self.output_dirs[ex_id], self.session_hour, self.signals)
            self.engines.append(engine)
            
            all_symbols = list(engine.markets.keys())
            target_symbols = [s for s in all_symbols if engine.is_valid_symbol(s)]
            
            with self.progress_lock:
                self.total_count += len(target_symbols)
            
            self.signals.log_message.emit(f"Found {len(target_symbols)} PERPETUAL markets on {ex_id.upper()}. Starting processing...")
            
            if ex_id == 'binance':
                max_workers = 6
            elif ex_id == 'bybit':
                max_workers = 10
            else:
                max_workers = 5
            
            failed_symbols = []
            market_results = {}

            def task(sym, current_pass):
                if self.stop_requested or engine.stop_requested:
                    return None
                success, data_modified, max_attempt_encountered = engine.process_market(sym, self.mode, current_pass, self.fix_date)
                
                res = {
                    'time': datetime.now().strftime('%Y-%m-%d %H:%M:%S.%f')[:-3],
                    'symbol': sym,
                    'filename': os.path.basename(engine.get_filename(sym)),
                    'run': current_pass if success else "Failed",
                    'attempt': max_attempt_encountered if success else "Failed",
                    'success': success,
                    'data_modified': data_modified
                }
                return sym, success, res

            with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as executor:
                futures = [executor.submit(task, sym, 1) for sym in target_symbols]
                
                for future in concurrent.futures.as_completed(futures):
                    if self.stop_requested or engine.stop_requested:
                        break
                    
                    result = future.result()
                    if result:
                        processed_sym, success, res = result
                        with self.progress_lock:
                            market_results[processed_sym] = res
                        if success is False:
                            failed_symbols.append(processed_sym)
                            
                    with self.progress_lock:
                        self.processed_count += 1
                        if self.total_count > 0:
                            progress = int((self.processed_count / self.total_count) * 100)
                            self.signals.progress_updated.emit(progress)
            
            # Second redownload pass
            if failed_symbols and not (self.stop_requested or engine.stop_requested):
                self.signals.log_message.emit(f"Waiting 5 seconds before starting the second pass for {len(failed_symbols)} missing markets on {ex_id.upper()}...")
                time.sleep(5)
                self.signals.log_message.emit(f"Starting the second pass (1 thread) on {ex_id.upper()}...")
                
                with self.progress_lock:
                    self.total_count += len(failed_symbols)
                
                with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor2:
                    futures2 = [executor2.submit(task, sym, 2) for sym in failed_symbols]
                    
                    for future in concurrent.futures.as_completed(futures2):
                        if self.stop_requested or engine.stop_requested:
                            break
                            
                        result = future.result()
                        if result:
                            processed_sym, success, res = result
                            with self.progress_lock:
                                market_results[processed_sym] = res
                                
                        with self.progress_lock:
                            self.processed_count += 1
                            if self.total_count > 0:
                                progress = int((self.processed_count / self.total_count) * 100)
                                self.signals.progress_updated.emit(progress)

            ex_end_time = datetime.now()
            ex_duration = ex_end_time - ex_start_time
            total_seconds = int(ex_duration.total_seconds())
            hours = total_seconds // 3600
            minutes = (total_seconds % 3600) // 60
            seconds = total_seconds % 60
            tenths = ex_duration.microseconds // 100000
            formatted_ex_time = f"{hours:02}:{minutes:02}:{seconds:02}.{tenths}"
            self.signals.log_message.emit(f"Finished {engine.sub_folder}. Processing time: {formatted_ex_time}")
            
            with self.progress_lock:
                self.exchange_results[ex_id] = {
                    'engine': engine,
                    'market_results': market_results,
                    'start_time': ex_start_time,
                    'end_time': ex_end_time,
                    'formatted_time': formatted_ex_time
                }
                    
        except Exception as e:
            self.signals.log_message.emit(f"CRITICAL ERROR on {ex_id.upper()}: {str(e)}")

    def run(self):
        start_time = datetime.now()
        
        with concurrent.futures.ThreadPoolExecutor(max_workers=len(self.exchange_ids)) as executor:
            exchange_futures = [executor.submit(self.process_exchange, ex_id) for ex_id in self.exchange_ids]
            concurrent.futures.wait(exchange_futures)

        end_time = datetime.now()
        duration = end_time - start_time
        
        total_seconds = int(duration.total_seconds())
        hours = total_seconds // 3600
        minutes = (total_seconds % 3600) // 60
        seconds = total_seconds % 60
        tenths = duration.microseconds // 100000
        
        formatted_time = f"{hours:02}:{minutes:02}:{seconds:02}.{tenths}"
        
        # --- GENERATE LOG FILES ---
        for ex_id, meta in self.exchange_results.items():
            engine = meta['engine']
            market_results = meta['market_results']
            ex_start_time = meta['start_time']
            ex_end_time = meta['end_time']
            formatted_ex_time = meta['formatted_time']
            
            logs_dir = os.path.join(engine.output_dir, "Logs")
            if not os.path.exists(logs_dir):
                os.makedirs(logs_dir)
                
            log_filename = os.path.join(logs_dir, ex_start_time.strftime('%Y-%m-%d_%H-%M-%S') + ".txt")
            
            # Sort results by time
            sorted_results = sorted(market_results.values(), key=lambda x: x['time'])
            
            # Filter results points
            # We want to log either modified (success + data_modified) or completely failed (success=False)
            results_to_log = [r for r in sorted_results if r['data_modified'] or not r['success']]
            failed_markets = [r for r in sorted_results if not r['success']]
            
            try:
                with open(log_filename, "w", encoding="utf-8-sig") as f:
                    f.write(f"Update started: {ex_start_time.strftime('%Y-%m-%d %H:%M:%S')}\n")
                    f.write(f"Update ended:   {ex_end_time.strftime('%Y-%m-%d %H:%M:%S')}\n")
                    f.write(f"Processing time: {formatted_ex_time}\n")
                    mode_str = "Update" if self.mode == 'update' else ("Redownload" if self.mode == 'redownload' else "Fill Gaps")
                    f.write(f"Mode: {mode_str}\n")
                    
                    start_date_str = self.fix_date if (self.fix_date and self.fix_date.strip()) else "None"
                    f.write(f"Start Date: {start_date_str}\n")
                    
                    f.write(f"Active markets on {engine.sub_folder}: {len(market_results)}\n")
                    
                    date_counts = {}
                    for r in market_results.values():
                        filepath = os.path.join(engine.output_dir, r['filename'])
                        try:
                            if os.path.exists(filepath):
                                with open(filepath, 'r') as csv_f:
                                    # Reading the entire file for accuracy (files are usually <100kb);
                                    # OS cache makes this read near-instantaneous.
                                    lines = csv_f.readlines()
                                    if lines:
                                        last_line = lines[-1].strip()
                                        if last_line:
                                            last_date = last_line.split(',')[0]
                                            date_counts[last_date] = date_counts.get(last_date, 0) + 1
                        except:
                            pass
                            
                    if date_counts:
                        most_recent = max(date_counts.keys())
                        f.write(f"Most recent date: {most_recent} found in {date_counts[most_recent]} markets\n")
                        
                        # --- Timezone and Session Info ---
                        tz_offset = engine.timezone_offset
                        session_close_utc = (24 - tz_offset) % 24
                        day_str = "next" if tz_offset <= 0 else "same"
                        
                        if tz_offset == 0: tz_desc = "UTC±0"
                        elif tz_offset > 0: tz_desc = f"UTC+{tz_offset}"
                        else: tz_desc = f"UTC{tz_offset}"
                        
                        f.write(f"Timezone: {tz_desc} (bar closes {session_close_utc:02d}:00 UTC on the {day_str} day)\n")
                        
                        try:
                            # Parse YYYYMMDD string to date
                            current_date = datetime.strptime(most_recent, '%Y%m%d')
                            day_adjust = 1 if tz_offset <= 0 else 0
                            
                            session_end_utc = datetime(current_date.year, current_date.month, current_date.day, 
                                                       session_close_utc, 0, 0, tzinfo=timezone.utc)
                            session_end_utc += timedelta(days=day_adjust)
                            session_start_utc = session_end_utc - timedelta(days=1)
                            
                            # Get system local timezone
                            local_tz = datetime.now().astimezone().tzinfo
                            session_start_local = session_start_utc.astimezone(local_tz)
                            session_end_local = session_end_utc.astimezone(local_tz)
                            
                            f.write(f"Data for {most_recent} includes 24h between:\n")
                            f.write(f"- UTC:   {session_start_utc.strftime('%Y-%m-%d %H:%M')} to {session_end_utc.strftime('%Y-%m-%d %H:%M')}\n")
                            f.write(f"- Local: {session_start_local.strftime('%Y-%m-%d %H:%M')} to {session_end_local.strftime('%Y-%m-%d %H:%M')}\n\n\n")
                        except:
                            f.write("\n\n")
                    else:
                        f.write("Most recent date: Unknown\n\n\n")

                    if failed_markets:
                        f.write("The update has failed for these markets:\n")
                        for r in failed_markets:
                            f.write(f"{r['filename']}\n")
                        f.write("\n\n")

                    if results_to_log:
                        # Pomocnicze funkcje do wyrównania szerokich znaków (np. chińskich)
                        def visual_len(text):
                            return sum(1.5 if unicodedata.east_asian_width(c) in 'WF' else 1 for c in text)

                        def pad_right(text, width):
                            pad_len = int(max(0, width - visual_len(text)))
                            return text + ' ' * pad_len
                        
                        def pad_center(text, width):
                            pad_len = int(max(0, width - visual_len(text)))
                            left = pad_len // 2
                            right = pad_len - left
                            return ' ' * left + text + ' ' * right

                        f.write(f"{'Time':<30} | {'Market':<30} | {'Run':^8} | {'Attempt':^7}\n")
                        f.write("-" * 30 + " | " + "-" * 30 + " | " + "-" * 8 + " | " + "-" * 7 + "\n")
                        for r in results_to_log:
                            t_pad = pad_right(str(r['time']), 30)
                            m_pad = pad_right(str(r['filename']), 30)
                            r_pad = pad_center(str(r['run']), 8)
                            a_pad = pad_center(str(r['attempt']), 7)
                            f.write(f"{t_pad} | {m_pad} | {r_pad} | {a_pad}\n")
            except Exception as e:
                self.signals.log_message.emit(f"Error saving log for {ex_id}: {e}")

        self.signals.log_message.emit("Process Finished.")
        self.signals.log_message.emit(f"Total processing time: {formatted_time} (HH:MM:SS.S)")
        self.signals.finished.emit()
        self.signals.progress_updated.emit(100)

    def stop(self):
        self.stop_requested = True
        for engine in self.engines:
            engine.stop_requested = True
        self.wait()

