    def init_dpi_scaling(self):
        """Initialize DPI scaling factors based on screen resolution and DPI settings.
        
        This ensures consistent visual appearance regardless of:
        - Screen resolution (1920x1080, 2560x1440, 3840x2160, etc.)
        - Windows DPI scaling (100%, 125%, 150%, 200%, etc.)
        
        The scaling formula: scaled_value = (base_value * resolution_factor) / device_pixel_ratio
        """
        screen = QApplication.primaryScreen()
        
        # Get device pixel ratio (DPI scaling factor)
        # 1.0 = 100% DPI, 1.25 = 125% DPI, 1.5 = 150% DPI, 2.0 = 200% DPI
        self.device_pixel_ratio = screen.devicePixelRatio()
        
        # Get screen geometry
        geometry = screen.geometry()
        self.screen_width = geometry.width()
        self.screen_height = geometry.height()
        
        # Calculate raw (physical) screen dimensions
        # This is the actual pixel count of the monitor
        self.raw_screen_width = geometry.width() * self.device_pixel_ratio
        self.raw_screen_height = geometry.height() * self.device_pixel_ratio
        
        # Calculate resolution factor relative to base resolution of 1920x1080
        # 1.0 for 1920x1080, 1.33 for 2560x1440, 2.0 for 3840x2160
        self.resolution_factor = self.raw_screen_width / 1920
        
        # Combined scale factor for UI elements (use shared function)
        self.scale_factor = get_scale_factor()
        
    def scale(self, base_value):
        """Scale a base value according to resolution and DPI settings.
        
        Args:
            base_value: The base value designed for 1920x1080 at 100% DPI
            
        Returns:
            Scaled integer value appropriate for current display settings
        """
        return int(base_value * self.scale_factor)
    
    def scale_font(self, base_pt):
        """Scale a font size in points according to resolution and DPI.
        
        Args:
            base_pt: Base font size in points for 1920x1080 at 100% DPI
            
        Returns:
            Scaled font size in points
        """
        # Font scaling needs to account for both resolution and DPI
        return int((base_pt * self.resolution_factor) / self.device_pixel_ratio)


