    def load_settings(self):
        settings_path = os.path.join(APP_DIR, 'settings_demo.json')
        
        # Get current drive letter (UPPERCASE)
        drive = os.path.splitdrive(APP_DIR)[0].upper()
        if not drive:
            drive = "C:"

        if not os.path.exists(settings_path):
            # Default paths for new installation
            self.path_binance.setText(f"{drive}/Binance_Data")
            self.path_bybit.setText(f"{drive}/Bybit_Data")
            
            # Default timezone UTC+0
            idx_utc = self.time_combo.findData(0)
            if idx_utc >= 0:
                self.time_combo.setCurrentIndex(idx_utc)

            # Init toggle
            self.toggle_binance_path(self.cb_binance.isChecked())
            self.toggle_bybit_path(self.cb_bybit.isChecked())
            return

        try:
            with open(settings_path, 'r', encoding='utf-8-sig') as f:
                data = json.load(f)

            self.cb_binance.setChecked(data.get('binance', True))
            self.cb_bybit.setChecked(data.get('bybit', True))
            
            self.path_binance.setText(data.get('binance_dir', data.get('output_dir', os.getcwd())).replace('\\', '/'))
            self.path_bybit.setText(data.get('bybit_dir', data.get('output_dir', os.getcwd())).replace('\\', '/'))

            # Init toggle
            self.toggle_binance_path(self.cb_binance.isChecked())
            self.toggle_bybit_path(self.cb_bybit.isChecked())

            # Forced UTC+0 for FREE version (ignores settings.json to prevent override)
            idx_utc = self.time_combo.findData(0)
            if idx_utc >= 0:
                self.time_combo.setCurrentIndex(idx_utc)

            mode = data.get('mode', 'update')
            if mode == 'redownload': self.rb_redownload.setChecked(True)
            elif mode == 'fill_gaps': self.rb_fill.setChecked(True)
            else: self.rb_update.setChecked(True)

            self.date_input.setText(data.get('start_date', ''))

        except Exception as e:
            self.log(f"Error loading settings: {e}")

    def closeEvent(self, event):
        data = {
            'binance': self.cb_binance.isChecked(),
            'bybit': self.cb_bybit.isChecked(),
            'binance_dir': self.path_binance.text(),
            'bybit_dir': self.path_bybit.text(),
            'timezone_offset': self.time_combo.currentData(),
            'mode': 'redownload' if self.rb_redownload.isChecked() else ('fill_gaps' if self.rb_fill.isChecked() else 'update'),
            'start_date': self.date_input.text()
        }
        
        settings_path = os.path.join(APP_DIR, 'settings_demo.json')
        try:
            with open(settings_path, 'w', encoding='utf-8-sig') as f:
                json.dump(data, f, indent=4, ensure_ascii=False)
        except Exception as e:
            print(f"Error saving settings: {e}")
            
        event.accept()

    def browse_folder(self, exchange):
        title = "Select Output Folder for Binance" if exchange == 'binance' else "Select Output Folder for Bybit"
